# Get case data
cases = var_functions.query_db_5

# Get account data
accounts = var_functions.query_db_8

# Clean up the data - remove leading # from IDs and trailing whitespace from status
cleaned_cases = []
for case in cases:
    cleaned_case = {}
    for key, value in case.items():
        if key == 'id' and isinstance(value, str) and value.startswith('#'):
            cleaned_case[key] = value[1:]
        elif key == 'accountid' and isinstance(value, str) and value.startswith('#'):
            cleaned_case[key] = value[1:]
        elif key == 'contactid' and isinstance(value, str) and value.startswith('#'):
            cleaned_case[key] = value[1:]
        elif key == 'status' and isinstance(value, str):
            cleaned_case[key] = value.strip()
        else:
            cleaned_case[key] = value
    cleaned_cases.append(cleaned_case)

cleaned_accounts = []
for account in accounts:
    cleaned_account = {}
    for key, value in account.items():
        if key == 'Id' and isinstance(value, str) and value.startswith('#'):
            cleaned_account[key] = value[1:]
        elif key == 'ShippingState' and isinstance(value, str):
            cleaned_account[key] = value.strip()
        else:
            cleaned_account[key] = value
    cleaned_accounts.append(cleaned_account)

# Create a dictionary mapping account IDs to states
account_to_state = {acc['Id']: acc.get('ShippingState') for acc in cleaned_accounts if acc.get('ShippingState')}

# Add state to cases
cases_with_state = []
for case in cleaned_cases:
    account_id = case.get('accountid')
    state = account_to_state.get(account_id)
    if state:
        case_with_state = case.copy()
        case_with_state['state'] = state
        cases_with_state.append(case_with_state)

print('__RESULT__:')
print(json.dumps({
    'total_cases': len(cleaned_cases),
    'cases_with_state': len(cases_with_state),
    'sample_cases': cases_with_state[:5],
    'states_found': list(set([case['state'] for case in cases_with_state]))
}))

