import json

# Get case data using locals() since the variable name contains special characters
cases = locals()['var_functions.query_db:5']

# Get account data
accounts = locals()['var_functions.query_db:8']

# Clean up the data - remove leading # from IDs and trailing whitespace from status
cleaned_cases = []
for case in cases:
    cleaned_case = {}
    for key, value in case.items():
        if key in ['id', 'accountid', 'contactid'] and isinstance(value, str) and value.startswith('#'):
            cleaned_case[key] = value[1:]
        elif key == 'status' and isinstance(value, str):
            cleaned_case[key] = value.strip()
        else:
            cleaned_case[key] = value
    cleaned_cases.append(cleaned_case)

cleaned_accounts = []
for account in accounts:
    cleaned_account = {}
    for key, value in account.items():
        if key == 'Id' and isinstance(value, str) and value.startswith('#'):
            cleaned_account[key] = value[1:]
        elif key == 'ShippingState' and isinstance(value, str):
            cleaned_account[key] = value.strip()
        else:
            cleaned_account[key] = value
    cleaned_accounts.append(cleaned_account)

# Create a dictionary mapping account IDs to states
account_to_state = {acc['Id']: acc.get('ShippingState') for acc in cleaned_accounts if acc.get('ShippingState')}

# Add state to cases
cases_with_state = []
for case in cleaned_cases:
    account_id = case.get('accountid')
    state = account_to_state.get(account_id)
    if state:
        case_with_state = case.copy()
        case_with_state['state'] = state
        cases_with_state.append(case_with_state)

# Calculate closure time and average by state
from datetime import datetime

state_closure_times = {}
for case in cases_with_state:
    try:
        created = datetime.fromisoformat(case['createddate'].replace('Z', '+00:00'))
        closed = datetime.fromisoformat(case['closeddate'].replace('Z', '+00:00'))
        closure_hours = (closed - created).total_seconds() / 3600

        state = case['state']
        if state not in state_closure_times:
            state_closure_times[state] = []
        state_closure_times[state].append(closure_hours)
    except Exception as e:
        continue

# Calculate average closure time per state
state_avg_closure = {}
for state, times in state_closure_times.items():
    if len(times) >= 3:  # Only include states with at least 3 cases
        state_avg_closure[state] = sum(times) / len(times)

# Sort by average closure time (fastest first)
sorted_states = sorted(state_avg_closure.items(), key=lambda x: x[1])

print('__RESULT__:')
print(json.dumps({
    'total_cases': len(cleaned_cases),
    'cases_with_state': len(cases_with_state),
    'states_with_data': len(state_avg_closure),
    'top_5_fastest_states': sorted_states[:5]
}))
